import React, { useState } from 'react'
import { useNavigate } from 'react-router-dom'

// useNavigate → gives a function to navigate programmatically (based on logic)
// use this when you can't use <Link> because the destination depends on a condition

function Login() {
    const [username, setUsername] = useState("")
    const [password, setPassword] = useState("")

    const navigate = useNavigate()

    function loginHandler(){
        // navigate() pushes a new path into browser history — back button will work
        if(username == "admin" && password == "admin"){
            navigate("/home")   // correct credentials → go to home
        }else{
            navigate("/error")  // wrong credentials  → go to error page
        }
    }
  return (
    <div>
      <input type='text' onChange={(e)=> setUsername(e.target.value)}/>
      <input type='text' onChange={(e)=> setPassword(e.target.value)}/>
      <button onClick={loginHandler}>login</button>
    </div>
  )
}

export default Login
